const items = $input.all();
const today = new Date();

function daysSince(dateStr) {
  if (!dateStr || dateStr.toString().trim() === '') return -1;
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return -1;
  return Math.floor((today - date) / (1000 * 60 * 60 * 24));
}

function isFalsy(val) {
  return !val || val.toString().trim() === '' || val.toString().toUpperCase() === 'FALSE';
}

return items.map(item => {
  const d = item.json;
  const correo = (d.correo || '').toString().trim();

  if (!correo) return { json: { ...d, accion: 'skip' } };

  const email1Sent = !isFalsy(d.email_1_enviado);
  const email2Sent = !isFalsy(d.email_2_enviado);
  const email3Sent = !isFalsy(d.email_3_enviado);
  const email4Sent = !isFalsy(d.email_4_enviado);

  let accion = 'skip';

  // Solo avanzar si la fecha del email anterior existe Y pasaron los días requeridos
  const dias1 = daysSince(d.fecha_email_1);
  const dias2 = daysSince(d.fecha_email_2);
  const dias3 = daysSince(d.fecha_email_3);

  if (email1Sent && !email2Sent && dias1 >= 3) {
    accion = 'email_2';
  } else if (email2Sent && !email3Sent && dias2 >= 3) {
    accion = 'email_3';
  } else if (email3Sent && !email4Sent && dias3 >= 5) {
    accion = 'email_4';
  }

  const nombre = (d.nombre || 'equipo').toString().split(' ')[0];

  return {
    json: {
      ...d,
      accion,
      _email_to: correo,
      _nombre: d.nombre || '',
      _nombre_short: nombre,
      _saludo: `Hola ${nombre}`
    }
  };
});

